{"index":{"notrun":".xat \u0645\u0644\u062d\u0648\u0638\u0647: \u0647\u0630\u0647 \u0627\u0644\u062f\u0631\u062f\u0634\u0647 \u0644\u0627 \u062a\u062f\u064a\u0631\u0647\u0627","promotedgroups":"\u0627\u0644\u062c\u0645\u0627\u0639\u0627\u062a \u0627\u0644\u0645\u0631\u0648\u062c\u0647","new":"\u061fxat \u062c\u062f\u064a\u062f \u0628\u0640","newt":"\u0633\u062c\u0644 \u062d\u0633\u0627\u0628. \u0642\u0645 \u0628\u0627\u0644\u0639\u062b\u0648\u0631 \u0639\u0644\u064a \u062f\u0631\u062f\u0634\u0647 \u062a\u0634\u0627\u0637\u0631 \u0627\u0644\u0645\u0635\u0627\u0644\u062d \u0627\u0644\u062e\u0627\u0635\u0647 \u0628\u0643 \u0648 \u0627\u0647\u062a\u0645\u0627\u0645\u0627\u062a\u0643. \u0642\u0645 \u0628\u0639\u0645\u0644 \u062f\u0631\u062f\u0634\u0647 \u062e\u0627\u0635\u0647 \u0628\u0643. \u0627\u062d\u0635\u0644 \u0648 \u062a\u0627\u062c\u0631 \u0627\u0644\u0642\u0648\u064a. \u0627\u0644\u0639\u0628 \u0644\u0639\u0628\u0647 \u062b\u0646\u0627\u0626\u064a\u0647","newb":"\u062a\u0639\u0644\u0645 \u0627\u0644\u0645\u0632\u064a\u062f","powers":"\u0627\u0644\u0642\u0648\u064a","powerst":".\u0648 \u0627\u0644\u0623\u064a\u0627\u0645 \u0644\u0634\u0631\u0627\u0621 \u0642\u0648\u064a \u0645\u0645\u064a\u0632\u0647 \u0644\u062f\u0631\u062f\u0634\u062a\u0643 xats \u064a\u0645\u0643\u0646\u0643 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\n \u0628\u0627\u0644\u0623\u0636\u0627\u0641\u0647 \u0627\u0644\u064a \u0645\u062c\u0645\u0648\u0639\u0647 \u0645\u0646 \u0627\u0644\u0623\u0628\u062a\u0633\u0627\u0645\u0627\u062a \u0627\u0644\u0645\u062e\u0635\u0635\u0647, \u0645\u0624\u062b\u0631\u0627\u062a \u0648 \u0642\u062f\u0631\u0627\u062a \u0645\u0645\u064a\u0632\u0647\n\u0648 \u0642\u0648\u064a \u0627\u0644\u0645\u062c\u0645\u0648\u0639\u0627\u062a \u0627\u0644\u062a\u064a \u062a\u0636\u064a\u0641 \u0645\u064a\u0632\u0627\u062a \u0627\u0636\u0627\u0641\u064a\u0647 \u0644\u062f\u0631\u062f\u0634\u062a\u0643\n<a href=\"http:\/\/util.xat.com\/wiki\/index.php\/Powers\">xat wiki<\/a> \u062a\u0639\u0644\u0645 \u0627\u0644\u0645\u0632\u064a\u062f \u0639\u0646 \u0643\u0644 \u0627\u0644\u0642\u0648\u064a \u0627\u0644\u0645\u062a\u0648\u0641\u0631\u0647 \u0641\u064a","powersb":"\u0627\u062d\u0635\u0644 \u0639\u0644\u064a \u0627\u0644\u0642\u0648\u064a","games":"\u0623\u0644\u0639\u0627\u0628","gamest":"\u0627\u0644\u0639\u0628 \u0636\u062f \u0627\u0635\u062f\u0642\u0627\u0626\u0643 \u0627\u0648 \u0639\u0634\u0648\u0627\u0626\u064a\u0646. \u062a\u0646\u0627\u0641\u0633 \u0644\u062a\u0643\u0648\u0646 \u0627\u0644\u0623\u0633\u0631\u0639 \u0628\u0627\u0644\u0623\u0639\u0627\u0628 \u0627\u0644\u0633\u0628\u0627\u0642\u0627\u062a \u0623\u0648 \u0627\u0644\u0647\u0631\u0628 \u0645\u0646 \u0627\u0644\u062d\u0638\u0631 \u0645\u0639 \u0623\u0644\u0639\u0627\u0628 \u0627\u0644\u062d\u0638\u0631. Doodle \u0647\u0648 \u062a\u0637\u0628\u064a\u0642 \u0631\u0633\u0645 \u062a\u0639\u0627\u0648\u0646\u064a \u062d\u0631. \u062f\u0648\u0648\u062f\u0644\u0631\u0627\u0633 \u062a\u0639\u0637\u064a \u0644\u0643 \u0631\u0633\u0645\u0647 \u062b\u0645 \u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u062a\u0635\u0648\u064a\u062a \n.\u0644\u0644\u0630\u064a \u0642\u0627\u0645 \u0628\u0623\u0641\u0636\u0644 \u0631\u0633\u0645\u0647. \u0627\u064a\u0636\u0627 \u0642\u0645 \u0628\u062a\u062c\u0631\u0628\u0647 \u0627\u0644\u0642\u0644\u0648\u0628 \u0642\u0648\u0647 \u0644\u0639\u0628\u0647 \u0627\u0644\u0623\u0648\u0631\u0627\u0642","gamesb":"\u0623\u0644\u0639\u0628 \u0627\u0644\u0623\u0646","xavi":"\u0627\u0644\u0645\u062a\u062d\u0631\u0643\u0647 xavi \u0631\u0633\u0648\u0645","xavit":".\u0648 \u0634\u0627\u0647\u062f\u0647\u0627 \u062a\u062a\u062d\u0631\u0643 \u0639\u0646\u062f\u0645\u0627 \u062a\u0643\u062a\u0628 xavi \u0635\u0645\u0645 \u0634\u062e\u0635\u064a\u0647 \u0643\u0631\u062a\u0648\u0646\u064a\u0647 \u0628\u0646\u0641\u0633\u0643 \u0645\u0639 \n<a href=\"http:\/\/xat.com\/web_gear\/chat\/Getxavis.php\">xavi \u0628\u0645\u062a\u062c\u0631 <\/a> \n xavi \u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u064a \u0627\u0644\u0623\u0643\u0633\u0633\u0648\u0627\u0631\u0627\u062a \u0627\u0644\u062e\u0627\u0635\u0647 \u0628\u0640\n.(xavi \u062a\u0637\u0644\u0628 \u0642\u0648\u0647)","xavib":"\u0627\u0644\u062e\u0627\u0635 \u0628\u0643 xavi \u0635\u0645\u0645","group":"xat \u0627\u0646\u0634\u0627\u0621 \u0645\u062c\u0645\u0648\u0639\u0647","groupt":"\u062f\u0631\u062f\u0634\u062a\u0643 \u0627\u0644\u062e\u0627\u0635\u0647 \u064a\u0645\u0643\u0646 \u0627\u0646 \u062a\u0643\u0648\u0646 \u0644\u0645\u0648\u0636\u0648\u0639 \u0645\u0639\u064a\u0646 (\u0645\u062b\u0644 \u0627\u0644\u0645\u0648\u0633\u064a\u0642\u064a, \u0627\u0646\u064a\u0645\u064a, \u0627\u0644\u0639\u0627\u0628 \u0627\u0644\u0641\u062f\u064a\u0648), \u0644\u0632\u0648\u0627\u0631 \u0645\u0648\u0642\u0639\u0643 \u0627\u0648 \u0644\u0645\u062c\u0631\u062f \u0644\u0643 \u0648 \u0623\u0635\u062f\u0642\u0627\u0626\u0643. \u064a\u0645\u0643\u0646\u0643 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0647\u0627 \u0627\u0648 \u062a\u0636\u0645\u064a\u0646\u0647\u0627 \u0641\u064a \u0645\u0648\u0642\u0639 \u0627\u0644\u0648\u064a\u0628\n.\u0627\u0644\u062e\u0627\u0635 \u0628\u0643. \u0627\u0644\u0645\u062c\u0645\u0648\u0639\u0627\u062a \u0642\u0627\u0628\u0644\u0647 \u0644\u0644\u062a\u062e\u0635\u064a\u0635 \u0628\u0627\u0644\u0643\u0627\u0645\u0644, \u0648 \u064a\u0645\u0643\u0646 \u0627\u0646 \u062a\u0643\u0648\u0646 \u0644\u0644\u0623\u0639\u0636\u0627\u0621 \u0641\u0642\u0637 \u0627\u0630\u0627 \u0643\u0646\u062a \u062a\u0631\u063a\u0628 \u0641\u064a \u062d\u0635\u0631\u0647\u0627 \u0644\u0623\u0635\u062f\u0642\u0627\u0626\u0643","groupb":"xat \u0627\u0646\u0634\u0627\u0621 \u0645\u062c\u0645\u0648\u0639\u0647","trade":"\u062a\u0627\u062c\u0631 \u0627\u0644\u0642\u0648\u064a","tradet":"\u064a\u0645\u0643\u0646\u0643 \u062a\u062c\u0627\u0631\u0647 \u0627\u0644\u0642\u0648\u064a \u0645\u0639 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645\u064a\u0646 \u0627\u0644\u0623\u062e\u0631\u064a\u0646 \u0628\u0627\u0644\u062f\u0631\u062f\u0634\u0627\u062a. \u0627\u0630\u0627 \u0643\u0646\u062a \u0645\u0627\u0647\u0631\u0627 \u064a\u0645\u0643\u0646\u0643 \u0643\u0633\u0628 \u0627\u0644\u0631\u0628\u062d, \u0627\u0634\u062a\u0631\u064a \u0627\u0644\u0642\u0648\u064a \u0628\u0633\u0639\u0631 \u0645\u0646\u062e\u0641\u0636 \u0648 \u0628\u064a\u0639 \u0628\u0633\u0639\u0631 \u0627\u0639\u0644\u064a.\n<a href=\"http:\/\/xat.com\/web_gear\/chat\/chats.php?type=trade\">xat \u062a\u062c\u0627\u0631\u0647<\/a> \u0647\u0648 \u0627\u0644\u0645\u0643\u0627\u0646 \u062d\u064a\u062b \u064a\u0644\u062a\u0642\u064a \u0627\u0644\u062a\u062c\u0627\u0631.","tradeb":"\u0628\u062f\u0621 \u0627\u0644\u062a\u062c\u0627\u0631\u0647","promomine":"\u062a\u0631\u0648\u064a\u062c \u0645\u062c\u0645\u0648\u0639\u062a\u064a","follow":"\u0627\u062a\u0628\u0639 \u0627\u0643\u0633\u0627\u062a \u0639\u0644\u064a"}}